/**
 * RegisterPage Component
 *
 * ユーザー登録ページ。
 * RegisterFormコンポーネントを統合し、登録成功時にダッシュボードへリダイレクトします。
 *
 * ルート: /register
 */

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { RegisterForm } from '../components';

/**
 * RegisterPageコンポーネント
 * 登録フォームとレイアウトを提供します
 */
const RegisterPage: React.FC = () => {
  const navigate = useNavigate();

  /**
   * 登録成功時のハンドラー
   */
  const handleRegisterSuccess = () => {
    // ダッシュボードにリダイレクト
    navigate('/', { replace: true });
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        {/* Logo / Title */}
        <h1 className="text-center text-3xl font-bold text-gray-900">User Auth System</h1>
        <h2 className="mt-6 text-center text-2xl font-semibold text-gray-700">
          Create your account
        </h2>
        <p className="mt-2 text-center text-sm text-gray-600">Join us today and get started</p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
          {/* Register Form */}
          <RegisterForm onSuccess={handleRegisterSuccess} />
        </div>
      </div>

      {/* Footer */}
      <div className="mt-8 text-center">
        <p className="text-xs text-gray-500">&copy; 2025 User Auth System. All rights reserved.</p>
      </div>
    </div>
  );
};

export default RegisterPage;
