/**
 * RegisterForm Component
 *
 * ユーザー登録フォームコンポーネント。
 * メールアドレス、パスワード、パスワード確認、利用規約同意の入力とバリデーションを提供します。
 *
 * 使用例:
 * ```tsx
 * <RegisterForm onSuccess={() => navigate('/dashboard')} />
 * ```
 */

import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import InputField from './InputField';
import Button from './Button';
import ErrorMessage from './ErrorMessage';
import { validateRegisterForm, calculatePasswordStrength } from '../utils/validation';
import { handleNetworkError } from '../utils/errors';
import type { RegisterFormData } from '../types';

export interface RegisterFormProps {
  /** 登録成功時のコールバック */
  onSuccess?: () => void;
  /** 登録失敗時のコールバック */
  onError?: (error: string) => void;
}

/**
 * RegisterFormコンポーネント
 * 新規ユーザー登録フォームを提供します
 */
const RegisterForm: React.FC<RegisterFormProps> = ({ onSuccess, onError }) => {
  const { register } = useAuth();
  const [formData, setFormData] = useState<RegisterFormData>({
    email: '',
    password: '',
    confirmPassword: '',
    acceptTerms: false,
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  // パスワード強度計算
  const passwordStrength = calculatePasswordStrength(formData.password);

  /**
   * 入力値変更ハンドラー
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
    // エラーをクリア
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }));
    }
    setSubmitError(null);
  };

  /**
   * フォーム送信ハンドラー
   */
  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitError(null);

    // バリデーション
    const validationErrors = validateRegisterForm(formData);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    setIsSubmitting(true);

    try {
      // 登録API呼び出し
      await register(formData.email, formData.password);

      // 成功時のコールバック
      if (onSuccess) {
        onSuccess();
      }
    } catch (error) {
      // エラーメッセージを取得
      const errorMessage = handleNetworkError(error);
      setSubmitError(errorMessage);

      // エラーコールバック
      if (onError) {
        onError(errorMessage);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  /**
   * パスワード強度インジケーターの色
   */
  const getStrengthColor = (strength: number): string => {
    if (strength === 0) return 'bg-gray-300';
    if (strength <= 2) return 'bg-red-500';
    if (strength === 3) return 'bg-yellow-500';
    return 'bg-green-500';
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4" noValidate>
      {/* Submit Error Message */}
      {submitError && <ErrorMessage message={submitError} variant="error" />}

      {/* Email Field */}
      <InputField
        type="email"
        name="email"
        label="Email Address"
        value={formData.email}
        onChange={handleChange}
        error={errors.email}
        placeholder="you@example.com"
        required
        autoComplete="email"
        disabled={isSubmitting}
      />

      {/* Password Field */}
      <div>
        <InputField
          type="password"
          name="password"
          label="Password"
          value={formData.password}
          onChange={handleChange}
          error={errors.password}
          placeholder="Enter a strong password"
          required
          autoComplete="new-password"
          disabled={isSubmitting}
        />

        {/* Password Strength Indicator */}
        {formData.password && (
          <div className="mt-2">
            <div className="flex items-center space-x-2">
              <div className="flex-1 bg-gray-200 rounded-full h-2">
                <div
                  className={`h-2 rounded-full transition-all ${getStrengthColor(
                    passwordStrength.strength
                  )}`}
                  style={{ width: `${(passwordStrength.strength / 5) * 100}%` }}
                />
              </div>
              <span className="text-xs text-gray-600 min-w-[60px]">{passwordStrength.label}</span>
            </div>
          </div>
        )}
      </div>

      {/* Confirm Password Field */}
      <InputField
        type="password"
        name="confirmPassword"
        label="Confirm Password"
        value={formData.confirmPassword}
        onChange={handleChange}
        error={errors.confirmPassword}
        placeholder="Re-enter your password"
        required
        autoComplete="new-password"
        disabled={isSubmitting}
      />

      {/* Accept Terms Checkbox */}
      <div>
        <div className="flex items-start">
          <input
            type="checkbox"
            name="acceptTerms"
            id="acceptTerms"
            checked={formData.acceptTerms}
            onChange={handleChange}
            disabled={isSubmitting}
            className="h-4 w-4 mt-1 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
          />
          <label htmlFor="acceptTerms" className="ml-2 block text-sm text-gray-700">
            I accept the{' '}
            <a
              href="/terms"
              target="_blank"
              rel="noopener noreferrer"
              className="text-primary-600 hover:text-primary-700 underline"
            >
              Terms and Conditions
            </a>
          </label>
        </div>
        {errors.acceptTerms && <p className="mt-1 text-sm text-red-600">{errors.acceptTerms}</p>}
      </div>

      {/* Submit Button */}
      <Button
        type="submit"
        variant="primary"
        fullWidth
        loading={isSubmitting}
        disabled={isSubmitting}
      >
        {isSubmitting ? 'Creating account...' : 'Create Account'}
      </Button>

      {/* Login Link */}
      <div className="text-center text-sm">
        <span className="text-gray-600">Already have an account? </span>
        <a href="/login" className="text-primary-600 hover:text-primary-700 underline font-medium">
          Login here
        </a>
      </div>
    </form>
  );
};

export default RegisterForm;
